CREATE TABLE IF NOT EXISTS users (    client_id VARCHAR(36) PRIMARY KEY,    name VARCHAR(100) NOT NULL,    created_at TIMESTAMP DEFAULT NOW());CREATE TABLE IF NOT EXISTS occupancy (    id SERIAL PRIMARY KEY,    seat_id INTEGER NOT NULL,    client_id VARCHAR(36) NOT NULL REFERENCES users(client_id) ON DELETE CASCADE,    date DATE NOT NULL DEFAULT CURRENT_DATE,    UNIQUE(seat_id, date));-- ?????? ??? ???????? ?????? ?? client_id ? ????CREATE INDEX IF NOT EXISTS idx_occupancy_client_date ON occupancy(client_id, date);